import React, { useState } from 'react';
import { catalogoInicial } from './data/cuentas';
import './styles/global.css';

function App() {
  const [bal, setBal] = useState(catalogoInicial);
  const [f, setF] = useState("23 de enero de 2026");
  const [input, setInput] = useState({ cuenta: 'bancos', monto: '', tipo: 'cargo' });

  const ver = (dia) => {
    let n = JSON.parse(JSON.stringify(catalogoInicial));
    if (dia === '28') {
      setF("28 de enero de 2026");
      n.activo.bancos = 1520; n.activo.inventarios = 10000; n.activo.ivaAcred = 480;
    } else if (dia === '30') {
      setF("30 de enero de 2026");
      n.activo.bancos = 1520; n.activo.inventarios = 10000; n.activo.ivaAcred = 480;
      n.activo.ivaPorAcred = 2240; n.activo.mobiliario = 35000; n.activo.gtosInst = 14000;
      n.activo.rentas = 5000; n.pasivo.acreedores = 16240;
    } else if (dia === '04') {
      setF("4 de febrero de 2026");
      n.activo.bancos = 6160; n.activo.inventarios = 10000; n.activo.ivaAcred = 1440;
      n.activo.ivaPorAcred = 2240; n.activo.mobiliario = 35000; n.activo.gtosInst = 18040;
      n.activo.rentas = 5000; n.pasivo.acreedores = 23240;
      n.pasivo.anticipoClientes = 4000; n.pasivo.ivaTrasladado = 640; n.capital = 1371000;
    } else {
      setF("23 de enero de 2026");
    }
    setBal(n);
  };

  const procesarEntrada = (e) => {
    e.preventDefault();
    let n = JSON.parse(JSON.stringify(bal));
    const valor = Number(input.monto);
    if (input.tipo === 'cargo') {
      if (n.activo[input.cuenta] !== undefined) n.activo[input.cuenta] += valor;
      else if (n.pasivo[input.cuenta] !== undefined) n.pasivo[input.cuenta] -= valor;
    } else {
      if (n.activo[input.cuenta] !== undefined) n.activo[input.cuenta] -= valor;
      else if (n.pasivo[input.cuenta] !== undefined) n.pasivo[input.cuenta] += valor;
    }
    setBal(n);
    setInput({ ...input, monto: '' });
  };

  const tA = Object.values(bal.activo).reduce((a, b) => a + (Number(b) || 0), 0);
  const tPC = Object.values(bal.pasivo).reduce((a, b) => a + (Number(b) || 0), 0) + (Number(bal.capital) || 0);

  return (
    <div className="app-layout">
      {/* SIDEBAR MODERNO */}
      <aside className="sidebar no-print">
        <h2 className="brand">FINTECH MAYI</h2>
        
        <div className="menu-section">
          <p className="section-title">HISTORIAL DE EVENTOS</p>
          <button className="btn-sidebar" onClick={() => ver('23')}>Apertura (23 Ene)</button>
          <button className="btn-sidebar" onClick={() => ver('28')}>Compra (28 Ene)</button>
          <button className="btn-sidebar" onClick={() => ver('30')}>Ajustes (30 Ene)</button>
          <button className="btn-sidebar" onClick={() => ver('04')}>Anticipo (04 Feb)</button>
        </div>

        <form className="data-card" onSubmit={procesarEntrada}>
          <p className="section-title">ENTRADA DE DATOS</p>
          <select value={input.cuenta} onChange={(e) => setInput({...input, cuenta: e.target.value})}>
            <option value="bancos">Bancos</option>
            <option value="inventarios">Inventarios</option>
            <option value="mobiliario">Mobiliario</option>
            <option value="acreedores">Acreedores</option>
          </select>
          <input type="number" placeholder="Monto" value={input.monto} onChange={(e) => setInput({...input, monto: e.target.value})} />
          <div className="toggle-group">
            <button type="button" onClick={() => setInput({...input, tipo: 'cargo'})} className={input.tipo === 'cargo' ? 'active' : ''}>Cargo</button>
            <button type="button" onClick={() => setInput({...input, tipo: 'abono'})} className={input.tipo === 'abono' ? 'active' : ''}>Abono</button>
          </div>
          <button type="submit" className="btn-primary">Registrar</button>
        </form>

        <button className="btn-outline" onClick={() => window.print()}>Generar Reporte PDF</button>
      </aside>

      {/* CONTENIDO PRINCIPAL ESTILO PAPER */}
      <main className="main-content">
        <div className="report-paper">
          <header className="report-header">
            <h1>COCINA ECONÓMICA MAYI</h1>
            <div className="report-badge">Balance General Profesional</div>
            <p className="report-date">Estado de Situación Financiera al {f}</p>
          </header>

          <div className="balance-grid">
            <div className="balance-column">
              <h3>ACTIVOS</h3>
              <p className="category-label">CIRCULANTE</p>
              <div className="data-row"><span>Caja</span><span>${bal.activo.caja.toLocaleString()}</span></div>
              <div className="data-row"><span>Bancos</span><span>${bal.activo.bancos.toLocaleString()}</span></div>
              <div className="data-row"><span>Inventarios</span><span>${bal.activo.inventarios.toLocaleString()}</span></div>
              
              <p className="category-label">NO CIRCULANTE</p>
              <div className="data-row"><span>Terrenos</span><span>${bal.activo.terrenos.toLocaleString()}</span></div>
              <div className="data-row"><span>Edificios</span><span>${bal.activo.edificios.toLocaleString()}</span></div>
              <div className="data-row"><span>Mobiliario y Eq.</span><span>${bal.activo.mobiliario.toLocaleString()}</span></div>
              
              <div className="total-row"><span>TOTAL ACTIVO</span><span>${tA.toLocaleString()}</span></div>
            </div>

            <div className="balance-column">
              <h3>PASIVO + CAPITAL</h3>
              <p className="category-label">CORTO PLAZO</p>
              <div className="data-row"><span>Acreedores Diversos</span><span>${bal.pasivo.acreedores.toLocaleString()}</span></div>
              <div className="data-row"><span>IVA Trasladado</span><span>${bal.pasivo.ivaTrasladado.toLocaleString()}</span></div>
              
              <p className="category-label">PATRIMONIO</p>
              <div className="data-row"><span>Capital Social</span><span>${bal.capital.toLocaleString()}</span></div>
              <div className="data-row utility"><span>Utilidad / Pérdida</span><span>$0</span></div>
              
              <div className="total-row"><span>TOTAL P + C</span><span>${tPC.toLocaleString()}</span></div>
            </div>
          </div>

          <footer className="report-footer">
             <div className="signature">
               <div className="sig-line"></div>
               <strong>Mauricio Alexander G. D.</strong>
               <span>ELABORÓ</span>
             </div>
             <div className="signature">
               <div className="sig-line"></div>
               <strong>Profa. Gonzalez Zuñiga Nuria</strong>
               <span>AUTORIZÓ</span>
             </div>
          </footer>
        </div>
      </main>
    </div>
  );
}

export default App;
